func (o *Animal) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "Adoptions":
		rels, ok := retrieved.(AdoptionSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.Adoptions = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "Contact":
		rel, ok := retrieved.(*Contact)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.Contact = rel

		if rel != nil {
			rel.R.Animals = AnimalSlice{o}
		}
		return nil
	case "AnimalBreeds":
		rels, ok := retrieved.(AnimalBreedSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.AnimalBreeds = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "AnimalPhotos":
		rels, ok := retrieved.(AnimalPhotoSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.AnimalPhotos = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "AnimalVideos":
		rels, ok := retrieved.(AnimalVideoSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.AnimalVideos = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "Colors":
		rels, ok := retrieved.(ColorSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.Colors = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "Microchip":
		rel, ok := retrieved.(*Microchip)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.Microchip = rel

		if rel != nil {
			rel.R.Animal = o
		}
		return nil
	case "Tags":
		rels, ok := retrieved.(TagSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.Tags = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	case "UserAnimalLikes":
		rels, ok := retrieved.(UserAnimalLikeSlice)
		if !ok {
			return fmt.Errorf("animal cannot load %T as %q", retrieved, name)
		}

		o.R.UserAnimalLikes = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Animal = o
			}
		}
		return nil
	default:
		return fmt.Errorf("animal has no relationship %q", name)
	}
}

type animalPreloader struct {
	Contact   func(...psql.PreloadOption) psql.Preloader
	Microchip func(...psql.PreloadOption) psql.Preloader
}

func buildAnimalPreloader() animalPreloader {
	return animalPreloader{
		Contact: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Contact, ContactSlice](orm.Relationship{
				Name: "Contact",
				Sides: []orm.RelSide{
					{
						From: TableNames.Animals,
						To:   TableNames.Contacts,
						FromColumns: []string{
							ColumnNames.Animals.ContactID,
						},
						ToColumns: []string{
							ColumnNames.Contacts.ID,
						},
					},
				},
			}, Contacts.Columns().Names(), opts...)
		},
		Microchip: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*Microchip, MicrochipSlice](orm.Relationship{
				Name: "Microchip",
				Sides: []orm.RelSide{
					{
						From: TableNames.Animals,
						To:   TableNames.Microchips,
						FromColumns: []string{
							ColumnNames.Animals.ID,
						},
						ToColumns: []string{
							ColumnNames.Microchips.AnimalID,
						},
					},
				},
			}, Microchips.Columns().Names(), opts...)
		},
	}
}

